using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options backed by the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1. Strongly-typed metadata retrieval — returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> typed = options.GetTypeInfo<Person>();
Console.WriteLine($"Typed info: {typed.Type.Name}, kind = {typed.Kind}");

// 2. Probe without throwing — TryGetTypeInfo returns false when metadata is unavailable
//    Use an options instance with NO resolver so nothing can be resolved.
var empty = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine() // no resolvers → resolves nothing
};

bool found = empty.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? probed);
Console.WriteLine($"TryGetTypeInfo on empty resolver: found = {found}, info = {probed?.Type.Name ?? "(null)"}");

// Also show a successful probe
bool found2 = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? probed2);
Console.WriteLine($"TryGetTypeInfo on full resolver:  found = {found2}, info = {probed2?.Type.Name ?? "(null)"}");

public record Person(string Name, int Age);
EOF

